// // This module compares two 4-bit numbers and outputs whether the first is less than or equal to the second.
module comparator(
    input [3:0] a,
    input [3:0] b,
    output gt,
    output eq,
    output lt
);
    assign gt = (a > b);
    assign eq = (a == b);
    assign lt = (a < b);
endmodule
